44→import React from 'react';
45→import { useChartContext, useRegister, type EChartExt } from './shared.js';
46→
47→function defineComponent<T extends ComponentOption>(ext: EChartExt) {
48→  return function ChartComponent(props: ComposeOption<T>) {
49→    const ctx = useChartContext();
50→
51→    useRegister((echarts) => {
52→      echarts.use(ext);
53→    });
54→
55→    React.useLayoutEffect(() => {
56→      ctx.options.push(props);
57→    });
58→
59→    return null;
60→  };
61→}
62→
