import type {
  BrushComponentOption,
  CalendarComponentOption,
  ComposeOption,
  DatasetComponentOption,
  DataZoomComponentOption,
  GeoComponentOption,
  GraphicComponentOption,
  LegendComponentOption,
  MarkAreaComponentOption,
  MarkLineComponentOption,
  MarkPointComponentOption,
  MatrixComponentOption,
  PolarComponentOption,
  SingleAxisComponentOption,
  TimelineComponentOption,
  TitleComponentOption,
  ToolboxComponentOption,
  TooltipComponentOption,
  VisualMapComponentOption,
} from 'echarts';
import {
  BrushComponent,
  CalendarComponent,
  DatasetComponent,
  DataZoomComponent,
  GeoComponent,
  GraphicComponent,
  LegendComponent,
  MarkAreaComponent,
  MarkLineComponent,
  MarkPointComponent,
  MatrixComponent,
  PolarComponent,
  SingleAxisComponent,
  TimelineComponent,
  TitleComponent,
  ToolboxComponent,
  TooltipComponent,
  TransformComponent,
  VisualMapComponent,
} from 'echarts/components';
import type { ComponentOption } from 'echarts/types/src/util/types.js';
import React from 'react';
import { useChartContext, useRegister, type EChartExt } from './shared.js';

function defineComponent<T extends ComponentOption>(ext: EChartExt) {
  return function ChartComponent(props: ComposeOption<T>) {
    const ctx = useChartContext();

    useRegister((echarts) => {
      echarts.use(ext);
    });

    React.useLayoutEffect(() => {
      ctx.options.push(props);
    });

    return null;
  };
}

export const Brush = /*#__PURE__*/ defineComponent<BrushComponentOption>([BrushComponent]);

