import { definePreview } from 'storybook/preview';

export default definePreview({
  parameters: {
    controls: {
      matchers: {
        color: /(background|color)$/i,
        date: /Date$/i,
      },
    },
    a11y: {
      test: 'todo',
    },
  },
});

import preview from '#.storybook/preview';
import { expect, fn } from 'storybook/test';

import { Button } from './Button';

const meta = preview.meta({
  component: Button,
  tags: ['ai-generated'],
  parameters: {
    layout: 'centered',
  },
  argTypes: {
    backgroundColor: { control: 'color' },
  },
  args: { onClick: fn() },
});

export const Primary = meta.story({
  args: {
    primary: true,
    label: 'Save',
  },
  play: async ({ canvas }) => {
    const button = canvas.getByRole('button', { name: /save/i });
    await expect(button).toBeVisible();
    await expect(button).toBeEnabled();
  },
});

export const Secondary = meta.story({
  args: {
    label: 'Cancel',
  },
  play: async ({ canvas }) => {
    const button = canvas.getByRole('button', { name: /cancel/i });
    await expect(button).toBeVisible();
  },
});

export const Large = meta.story({
  args: {
    size: 'large',
    label: 'Large Button',
  },
  play: async ({ canvas }) => {
    const button = canvas.getByRole('button', { name: /large button/i });
    await expect(button).toBeVisible();
  },
});

export const Small = meta.story({
  args: {
    size: 'small',
    label: 'Small Button',
  },
  play: async ({ canvas }) => {
    const button = canvas.getByRole('button', { name: /small button/i });
    await expect(button).toBeVisible();
  },
});

export const CssCheck = meta.story({
  args: {
    primary: true,
    label: 'Submit',
  },
  play: async ({ canvas }) => {
    const button = canvas.getByRole('button', { name: /submit/i });
    // .storybook-button--primary uses background-color: #555ab9 — fails if CSS did not load.
    await expect(getComputedStyle(button).backgroundColor).toBe('rgb(85, 90, 185)');
  },
});

import preview from '#.storybook/preview';
import { expect, fn } from 'storybook/test';

import { Header } from './Header';

const meta = preview.meta({
  component: Header,
  tags: ['ai-generated'],
  parameters: {
    layout: 'fullscreen',
  },
  args: {
    onLogin: fn(),
    onLogout: fn(),
    onCreateAccount: fn(),
  },
});

export const LoggedIn = meta.story({
  args: {
    user: {
      name: 'Jane Doe',
    },
  },
  play: async ({ canvas }) => {
    await expect(canvas.getByText('Welcome,')).toBeVisible();
    await expect(canvas.getByText('Jane Doe')).toBeVisible();
    await expect(canvas.getByRole('button', { name: /log out/i })).toBeVisible();
  },
});

export const LoggedOut = meta.story({
  play: async ({ canvas }) => {
    await expect(canvas.getByRole('button', { name: /log in/i })).toBeVisible();
    await expect(canvas.getByRole('button', { name: /sign up/i })).toBeVisible();
  },
});

export const ClickLogin = meta.story({
  play: async ({ canvas, userEvent, args }) => {
    const loginButton = canvas.getByRole('button', { name: /log in/i });
    await userEvent.click(loginButton);
    await expect(args.onLogin).toHaveBeenCalled();
  },
});

import preview from '#.storybook/preview';
import { expect } from 'storybook/test';

import { Page } from './Page';

const meta = preview.meta({
  component: Page,
  tags: ['ai-generated'],
  parameters: {
    layout: 'fullscreen',
  },
});

export const Default = meta.story({
  play: async ({ canvas }) => {
    await expect(canvas.getByRole('heading', { name: /pages in storybook/i })).toBeVisible();
    await expect(canvas.getByRole('button', { name: /log in/i })).toBeVisible();
  },
});

export const LoggedIn = meta.story({
  play: async ({ canvas, userEvent }) => {
    const loginButton = canvas.getByRole('button', { name: /log in/i });
    await expect(loginButton).toBeVisible();
    await userEvent.click(loginButton);
    await expect(loginButton).not.toBeInTheDocument();
    const logoutButton = canvas.getByRole('button', { name: /log out/i });
    await expect(logoutButton).toBeVisible();
  },
});

export const SignUp = meta.story({
  play: async ({ canvas, userEvent }) => {
    const signUpButton = canvas.getByRole('button', { name: /sign up/i });
    await userEvent.click(signUpButton);
    await expect(canvas.getByText('Jane Doe')).toBeVisible();
  },
});

import preview from '#.storybook/preview';
import { expect } from 'storybook/test';
import { BarChart, CanvasRenderer, Legend, Title, Tooltip } from '@fanciers/echarts-react';

const chartStyle = { width: 600, height: 400 };

